import java.util.*;

// Implementing Comparable
class Student implements Comparable<Student> {
    private int id;
    private String name;
    private double gpa;

    Student(int id, String name, double gpa) {
        this.id = id;
        this.name = name;
        this.gpa = gpa;
    }

    // Natural ordering: by id
    @Override
    public int compareTo(Student other) {
        return Integer.compare(this.id, other.id);
    }

    @Override
    public String toString() {
        return String.format("Student{id=%d, name='%s', gpa=%.2f}", id, name, gpa);
    }
}

// Comparator for sorting by name
class NameComparator implements Comparator<Student> {
    @Override
    public int compare(Student s1, Student s2) {
        return s1.name.compareTo(s2.name);
    }
}

// Comparator for sorting by GPA
class GPAComparator implements Comparator<Student> {
    @Override
    public int compare(Student s1, Student s2) {
        return Double.compare(s1.gpa, s2.gpa);
    }
}

// Comparator with multiple fields
class MultiFieldComparator implements Comparator<Student> {
    @Override
    public int compare(Student s1, Student s2) {
        // First by GPA (descending)
        int gpaCompare = Double.compare(s2.gpa, s1.gpa);
        if (gpaCompare != 0) return gpaCompare;
        // Then by name
        return s1.name.compareTo(s2.name);
    }
}

public class ComparableComparatorExample {
    public static void main(String[] args) {
        // Creating students
        List<Student> students = Arrays.asList(
            new Student(3, "Charlie", 3.95),
            new Student(1, "Alice", 3.75),
            new Student(4, "Diana", 3.50),
            new Student(2, "Bob", 3.20)
        );

        System.out.println("Original: " + students);

        // 1. Natural ordering (Comparable)
        System.out.println("=== Natural Order (by ID) ===");
        Collections.sort(students);
        System.out.println("Sorted by ID: " + students);

        // 2. Comparator
        System.out.println("=== By Name ===");
        Collections.sort(students, new NameComparator());
        System.out.println("Sorted by Name: " + students);

        // 3. Another Comparator
        System.out.println("=== By GPA ===");
        Collections.sort(students, new GPAComparator());
        System.out.println("Sorted by GPA: " + students);

        // 4. Multiple fields
        System.out.println("=== By GPA (desc) then Name ===");
        Collections.sort(students, new MultiFieldComparator());
        System.out.println("Sorted by GPA desc, then name: " + students);

        // 5. Using Comparator with lambda (Java 8+)
        System.out.println("=== Lambda Comparator ===");
        students.sort((s1, s2) -> s1.name.compareTo(s2.name));
        System.out.println("Sorted by name (lambda): " + students);

        // 6. Comparator utility methods (Java 8+)
        System.out.println("=== Comparator Utilities ===");
        students.sort(Comparator.comparing(Student::getName));
        System.out.println("By name: " + students);

        students.sort(Comparator.comparing(Student::getGpa).reversed());
        System.out.println("By GPA desc: " + students);

        // 7. Sorting arrays
        System.out.println("=== Arrays ===");
        Student[] studentArray = students.toArray(new Student[0]);
        Arrays.sort(studentArray, new NameComparator());
        System.out.println("Array sorted by name: " + Arrays.toString(studentArray));

        // 8. Collections with Comparator
        System.out.println("=== Collections ===");
        TreeSet<Student> sortedByGPA = new TreeSet<>(new GPAComparator());
        sortedByGPA.addAll(students);
        System.out.println("TreeSet sorted by GPA: " + sortedByGPA);
    }
}

// Helper methods for lambda
class Student {
    // ... fields as above

    public String getName() { return name; }
    public double getGpa() { return gpa; }
}

phase2.brokenCode:
import java.util.*;

class Person {
    String name;
    int age;

    Person(String name, int age) {
        this.name = name;
        this.age = age;
    }
}

public class Test {
    public static void main(String[] args) {
        ArrayList<Person> people = new ArrayList<>();
        people.add(new Person("Alice", 25));
        people.add(new Person("Bob", 30));

        // Person doesn't implement Comparable
        Collections.sort(people);  // ERROR!
    }
}

phase2.explanation:
Person doesn't implement Comparable, so it can't be sorted with sort(list)!

FIX: Either implement Comparable:
class Person implements Comparable<Person> {
    @Override
    public int compareTo(Person other) {
        return this.age - other.age;
    }
}

Or use Comparator:
Collections.sort(people, (p1, p2) -> p1.age - p2.age);

For TreeSet, you also need Comparable or a Comparator provided in constructor.

Always choose the right sorting approach!

