import java.util.*;

class Product implements Comparable<Product> {
    int id;
    String name;
    double price;

    Product(int id, String name, double price) {
        this.id = id;
        this.name = name;
        this.price = price;
    }

    @Override
    public int compareTo(Product other) {
        return Integer.compare(this.id, other.id);
    }

    @Override
    public String toString() {
        return String.format("Product{id=%d, name='%s', price=%.2f}", id, name, price);
    }
}

class NameComparator implements Comparator<Product> {
    @Override
    public int compare(Product p1, Product p2) {
        return p1.name.compareTo(p2.name);
    }
}

class PriceComparator implements Comparator<Product> {
    @Override
    public int compare(Product p1, Product p2) {
        return Double.compare(p1.price, p2.price);
    }
}

public class Main {
    public static void main(String[] args) {
        List<Product> products = Arrays.asList(
            new Product(3, "Laptop", 1200.00),
            new Product(1, "Phone", 800.00),
            new Product(4, "Tablet", 500.00),
            new Product(2, "Monitor", 300.00)
        );

        System.out.println("Original: " + products);

        Collections.sort(products);
        System.out.println("By ID: " + products);

        Collections.sort(products, new NameComparator());
        System.out.println("By Name: " + products);

        Collections.sort(products, new PriceComparator());
        System.out.println("By Price: " + products);
    }
}
